class Solution {
    public int peopleAwareOfSecret(int n, int delay, int forget) {
        final int MOD = (int)1e9 + 7;
        int[] dp = new int[n + 1];
        dp[1] = 1;
        for (int i = 2; i <= n; i++) {
            for (int j = Math.max(1, i - forget); j <= i - delay; j++) {
                dp[i] = (dp[i] + dp[j]) % MOD;
            }
        }
        return dp[n];
    }
}
